// --- UI Simulation (for demonstration purposes) ---
document.addEventListener('DOMContentLoaded', () => {
    const loginForm = document.getElementById('loginForm');
    const usernameInput = document.getElementById('username');
    const passwordInput = document.getElementById('password');
    const rememberMeCheckbox = document.getElementById('rememberMe');
    const loginStatusDiv = document.getElementById('loginStatus');
    const logoutBtn = document.getElementById('logoutBtn');
    const loggedInUserSpan = document.getElementById('loggedInUser');
    const loggedInPanel = document.getElementById('loggedInPanel');
    const loginPanel = document.getElementById('loginPanel');

    if (loginForm) {
        loginForm.addEventListener('submit', (event) => {
            event.preventDefault();
            const username = usernameInput.value;
            const password = passwordInput.value;
            const remember = rememberMeCheckbox.checked;
            handleLogin(username, password, remember);
        });
    }

    if (logoutBtn) {
        logoutBtn.addEventListener('click', handleLogout);
    }

    function displayLoggedInState(username) {
        if (loggedInPanel && loginPanel && loggedInUserSpan) {
            loggedInPanel.style.display = 'block';
            loginPanel.style.display = 'none';
            loggedInUserSpan.textContent = username;
            loginStatusDiv.textContent = '';
            usernameInput.value = '';
            passwordInput.value = '';
            rememberMeCheckbox.checked = false;
        }
    }

    function displayLoggedOutState() {
        if (loggedInPanel && loginPanel) {
            loggedInPanel.style.display = 'none';
            loginPanel.style.display = 'block';
            loggedInUserSpan.textContent = '';
            loginStatusDiv.textContent = 'You have been logged out.';
        }
    }

    function displayLoginError(message) {
        if (loginStatusDiv) {
            loginStatusDiv.textContent = message;
            loginStatusDiv.style.color = 'red';
        }
    }

    // On page load, try to auto-login
    if (!attemptAutoLogin()) {
        displayLoggedOutState(); // If auto-login fails, show login form
    }
});

